def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        bonus = 0
        for j in range(1, 11):
            threshold = j * 0.1
            if ratio <= threshold:
                score += (11 - j) * np.log(j + 1) * np.exp(-ratio * j)
                if j % 2 == 0:
                    bonus += np.sqrt(j) * (1 - ratio)
                else:
                    penalty += j * ratio * 0.1
            else:
                penalty += j * np.sqrt(ratio) * (j / 10)
                if j % 3 == 0:
                    penalty += np.log(j + 1) * ratio
        if capacity % 3 == 0:
            score *= 1.15
            penalty *= 0.85
        elif capacity % 5 == 0:
            score *= 0.85
            penalty *= 1.15
        else:
            score *= 1.0
            penalty *= 1.0
        for k in range(1, 4):
            if ratio < 0.3 * k:
                bonus += np.sin(k * ratio * np.pi) * 2
            else:
                penalty += np.cos(k * ratio * np.pi) * 1.5
        final_score = score + bonus - penalty
        if final_score < 0:
            final_score = 0
        priorities[i] = final_score
    return priorities
